@PostMapping("/updateStatus")
public ResponseEntity<?> updateStatus(@RequestBody UpdateStatusRequest updateStatusRequest) {
    boolean updateSuccess = acceptanceCustomerService.updateStatus(updateStatusRequest);
    if (updateSuccess) {
        return ResponseEntity.ok(Collections.singletonMap("message", "状态更新成功！"));
